const switchNode = $input.all();
const telegramTrigger = $("Telegram Trigger").all();

const agentOutput = switchNode[0]?.json?.output || "";

if (!agentOutput.includes("PEDIDO_CONFIRMADO")) {
  return [];
}

const extractLine = (text, labelPattern) => {
  const regex = new RegExp(`(?:${labelPattern}):\\s*(.+)`, "i");
  const match = text.match(regex);
  return match ? match[1].trim() : "";
};

const chatId = telegramTrigger[0]?.json?.message?.chat?.id?.toString() || "";
const telegramName = telegramTrigger[0]?.json?.message?.chat?.first_name || "";

const nombre = extractLine(agentOutput, "Nombre") || telegramName;
const hora_recogida = extractLine(agentOutput, "Hora de recogida|Hora de Recogida");
const telefono = extractLine(agentOutput, "Teléfono|Telefono");

const productosLine = extractLine(agentOutput, "Productos|Producto");

const productosParseados = [];
const regex = /([^,(]+?)\s*\((\d+)\)/g;
let m;
while ((m = regex.exec(productosLine)) !== null) {
  productosParseados.push({
    producto: m[1].trim(),
    cantidad: parseInt(m[2], 10),
  });
}

if (productosParseados.length === 0 && productosLine) {
  productosParseados.push({ producto: productosLine, cantidad: 1 });
}

const pedidoTempId = `ord-${Date.now()}-${Math.floor(Math.random() * 9000) + 1000}`;
const fechaSolicitud = new Date().toISOString();

return productosParseados.map(({ producto, cantidad }) => ({
  json: {
    pedido_temp_id: pedidoTempId,
    nombre,
    producto,
    cantidad,
    hora_recogida,
    telefono,
    chat_id_cliente: chatId,
    estado: "PENDIENTE",
    fecha_solicitud: fechaSolicitud,
  },
}));

