// runOnceForAllItems
const supabaseItems = $input.all();
const parsedItems = $('Code - Parsear datos del pedido').all();

const stockMap = {};
for (const item of supabaseItems) {
  const p = item.json;
  if (p && p.nombre) {
    stockMap[p.nombre.toLowerCase().trim()] = {
      stock: p.stock ?? 0,
      id: p.id ?? null,
    };
  }
}

const base = parsedItems[0].json;

const productosList = [];
const productosSinStock = [];
const productosConStock = [];

for (const item of parsedItems) {
  const { producto, cantidad } = item.json;
  const key = producto.toLowerCase().trim();
  const info = stockMap[key] || { stock: 0, id: null };
  const suficiente = info.stock >= cantidad;
  const entry = {
    producto,
    cantidad,
    stock_disponible: info.stock,
    producto_id: info.id,
    suficiente,
  };
  productosList.push(entry);
  (suficiente ? productosConStock : productosSinStock).push(entry);
}

const stockSuficiente = productosSinStock.length === 0;

const productosTexto = productosList
  .map(p => `   • ${p.producto} x${p.cantidad}`)
  .join("\n");

let mensajeSinStock = "";
if (!stockSuficiente) {
  const lineas = productosSinStock
    .map(p => `❌ ${p.producto} — pediste ${p.cantidad}, solo hay ${p.stock_disponible} disponibles`)
    .join("\n");
  if (productosConStock.length > 0) {
    mensajeSinStock =
      `⚠️ Algunos productos de tu pedido no tienen stock suficiente:\n\n${lineas}\n\n` +
      `Los demás productos sí tienen stock. ¿Quieres ajustar las cantidades?\n` +
      `Escríbeme con los cambios y con gusto te ayudo. 😊`;
  } else {
    mensajeSinStock =
      `⚠️ Lo sentimos, ninguno de los productos de tu pedido tiene stock suficiente:\n\n${lineas}\n\n` +
      `¿Quieres ajustar las cantidades o elegir otros productos?\n` +
      `Escríbeme y con gusto te ayudo. 😊`;
  }
}

return [{
  json: {
    pedido_temp_id: base.pedido_temp_id,
    nombre: base.nombre,
    hora_recogida: base.hora_recogida,
    telefono: base.telefono,
    chat_id_cliente: base.chat_id_cliente,
    fecha_solicitud: base.fecha_solicitud,
    estado: base.estado,
    stock_suficiente: stockSuficiente,
    productos_list: productosList,
    productos_sin_stock: productosSinStock,
    productos_con_stock: productosConStock,
    productos_texto: productosTexto,
    mensaje_sin_stock: mensajeSinStock,
  },
}];

const clienteId = $input.first().json.cliente_id;
const convId = $input.first().json.conversacion_id;
const evalData = $('Code - Evaluar Stock').first().json;

return evalData.productos_list.map(p => ({
  json: {
    cliente_id: clienteId,
    conversacion_id: convId,
    producto_id: p.producto_id,
    cantidad: p.cantidad,
    pedido_temp_id: evalData.pedido_temp_id,
    hora_recogida: evalData.hora_recogida,
  }
}));

const genData = $('Code - Generar Numero de Pedido').first().json;
return genData.productos_list.map(p => ({
