const texto = ($json.data.text || '').trim();
const evalData = $('Code - Evaluar Stock').first().json;

const motivos = {
  '1': {
    mensaje: 'No contamos con el stock suficiente para tu pedido en este momento. Puedes intentar con una cantidad menor o visitarnos en tienda.',
    razon: 'Sin stock disponible',
  },
  '2': {
    mensaje: 'Estamos fuera de nuestro horario de atención. Te invitamos a realizar tu pedido durante nuestro horario habitual.',
    razon: 'Fuera de horario de atención',
  },
  '3': {
    mensaje: 'Hubo un inconveniente con tu pedido y no pudimos procesarlo. Por favor contáctanos directamente para que podamos ayudarte.',
    razon: 'Error en el pedido',
  },
  '4': {
    mensaje: 'Por el momento no podemos procesar tu pedido. Te invitamos a contactarnos directamente para más información.',
    razon: 'Otro motivo',
  },
};

const sel = motivos[texto] || motivos['4'];

return [{
  json: {
    mensaje_rechazo: sel.mensaje,
    rejection_reason: sel.razon,
    chat_id_cliente: evalData.chat_id_cliente,
    pedido_temp_id: evalData.pedido_temp_id,
  }
}];
